// ─── Helpers ──────────────────────────────────────────────────────────────────

/**
 * Get the full name of a co-borrower with salutation prefix
 */
function getCoborrowFullName(cb: CoBorrower): string {
  if (cb.salutation && cb.salutation.trim()) {
    return `${cb.salutation} ${cb.name}`;
  }
  return cb.name;
}

/**
 * Increment the serial number in a reference number
 * Format: SBI/13042/25-26/MAR/001 → SBI/13042/25-26/MAR/002
 */
function incrementRefNumber(refNo: string): string {
  if (!refNo || !refNo.includes("/")) return refNo;
  const parts = refNo.split("/");
  if (parts.length !== 5) return refNo;
  
  const lastPart = parts[4];
  const currentSerial = parseInt(lastPart, 10);
  if (isNaN(currentSerial)) return refNo;
  
  const nextSerial = String(currentSerial + 1).padStart(lastPart.length, "0");
  parts[4] = nextSerial;
  return parts.join("/");
}

function fmt(dateStr: string): string {
  if (!dateStr) return "";
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return dateStr;
  return d.toLocaleDateString("en-IN", { day: "2-digit", month: "2-digit", year: "numeric" });
}

function fmtCurrency(n: number): string {
  if (!n) return "—";
  return new Intl.NumberFormat("en-IN", { style: "currency", currency: "INR", maximumFractionDigits: 0 }).format(n);
}

function ordinalDate(dateStr: string): string {
  if (!dateStr) return "___________";
  // Accept DD/MM/YYYY or ISO
  let d: Date;
  if (dateStr.includes("/")) {
    const [dd, mm, yyyy] = dateStr.split("/");
    d = new Date(`${yyyy}-${mm}-${dd}`);
  } else {
    d = new Date(dateStr);
  }
  if (isNaN(d.getTime())) return dateStr;
  const day = d.getDate();
  const suffix = day === 1 || day === 21 || day === 31 ? "st" : day === 2 || day === 22 ? "nd" : day === 3 || day === 23 ? "rd" : "th";
  const month = d.toLocaleDateString("en-IN", { month: "long" });
  const year = d.getFullYear();
  return `${day}${suffix} ${month} ${year}`;
}

function todayDDMMYYYY(): string {
  return new Date().toLocaleDateString("en-IN", { day: "2-digit", month: "2-digit", year: "numeric" });
}

function todayOrdinal(): string {
  return ordinalDate(new Date().toISOString());
}

function buildAddress(loan: LoanDataRecord): string {
  return [loan.Shadow_Add1, loan.Shadow_Add2, loan.Shadow_Add3, loan.Shadow_Add4, loan.Shadow_PostCode]
    .map(p => (p || "").trim()).filter(Boolean).join(", ") || "";
}

function detectNocType(loanCategory: string, acctDesc: string): "general" | "home" | "vehicle" {
  const cat = (loanCategory || "").toLowerCase();
  const desc = (acctDesc || "").toLowerCase();
  if (cat.includes("home") || desc.includes("home") || desc.includes("hl") || desc.includes("suraksha") || desc.includes("maxgain")) return "home";
  if (cat.includes("vehicle") || cat.includes("auto") || cat.includes("car") || desc.includes("car") || desc.includes("vehicle") || desc.includes("auto")) return "vehicle";
  return "general";
}

function getLoanTypeLabel(loanCategory: string, acctDesc: string): string {
  const cat = (loanCategory || "").toLowerCase();
  if (cat.includes("home")) return "Home Loan";
  if (cat.includes("vehicle") || cat.includes("auto") || cat.includes("car")) return "Auto Loan";
  if (cat.includes("personal") || cat.includes("xpress")) return "Personal Loan";
  if (cat.includes("pension")) return "Pension Loan";
  if (cat.includes("gold")) return "Gold Loan";
  if (cat.includes("education")) return "Education Loan";
  if (cat.includes("pm surya") || cat.includes("pmsg") || cat.includes("solar")) return "PM Surya Ghar Loan";
  if (cat.includes("msme") || cat.includes("business")) return "Business Loan";
  return acctDesc || "Loan";
}

// ─── Extract salutation title from customer name ──────────────────────────────

/**
 * Detects a salutation prefix in a raw customer name (e.g. "MR JOHN DOE")
 * and returns the normalised title and the name stripped of the prefix.
 */
function extractTitleAndName(fullName: string): { title: string; name: string } {
  const trimmed = (fullName || "").trim();
  const upper = trimmed.toUpperCase();
  const titleMap: Array<{ prefix: string; title: string }> = [
    { prefix: "SMT. ", title: "Smt." },
    { prefix: "SMT ", title: "Smt." },
    { prefix: "SHRI ", title: "Shri" },
    { prefix: "MRS. ", title: "Mrs." },
    { prefix: "MRS ", title: "Mrs." },
    { prefix: "MS. ", title: "Ms." },
    { prefix: "MS ", title: "Ms." },
    { prefix: "MR. ", title: "Mr." },
    { prefix: "MR ", title: "Mr." },
    { prefix: "DR. ", title: "Dr." },
    { prefix: "DR ", title: "Dr." },
  ];
  for (const { prefix, title } of titleMap) {
    if (upper.startsWith(prefix)) {
      return { title, name: trimmed.slice(prefix.length).trim() };
    }
  }
  return { title: "", name: trimmed };
}

